mapper.select:
SELECT e.EMPLOYEE_ID, e.EMPLOYEE_NO, e.EMPLOYEE_NAME, e.EMPLOYEE_ROLE, e.EMPLOYEE_PHONE, e.EMPLOYEE_EMAIL, e.PROFILE_IMG, e.EMPLOYEE_STATUS, d.DEPT_NAME, p.POSITION_NAME, CASE WHEN a.ATTENDANCE_STATUS = 'LEAVE' THEN 'LEAVE' WHEN a.ATTENDANCE_ID IS NULL THEN 'NONE' WHEN a.CHECK_OUT_TIME IS NOT NULL THEN 'DONE' ELSE 'WORKING' END AS WORK_STATUS FROM EMPLOYEE e LEFT JOIN DEPARTMENT d ON d.DEPT_ID = e.DEPT_ID LEFT JOIN `POSITION` p ON p.POSITION_ID = e.POSITION_ID LEFT JOIN ATTENDANCE a ON a.EMPLOYEE_ID = e.EMPLOYEE_ID AND a.WORK_DATE = CURDATE() WHERE e.EMPLOYEE_STATUS = 'ACTIVE'
AND e.DEPT_ID = #{deptId}
ORDER BY p.POSITION_RANK, e.EMPLOYEE_NAME

SELECT e.EMPLOYEE_ID, e.EMPLOYEE_NO, e.EMPLOYEE_NAME, e.EMPLOYEE_ROLE, e.EMPLOYEE_PHONE, e.EMPLOYEE_EMAIL, e.PROFILE_IMG, e.EMPLOYEE_STATUS, d.DEPT_NAME, p.POSITION_NAME FROM EMPLOYEE e
LEFT JOIN DEPARTMENT d ON d.DEPT_ID = e.DEPT_ID LEFT JOIN `POSITION` p ON p.POSITION_ID = e.POSITION_ID WHERE e.EMPLOYEE_ID = #{employeeId}
AND e.EMPLOYEE_STATUS = 'ACTIVE'

